class Program
{
    static int Sum(params int[] nums)
    {
        int total = 0;
        foreach (int n in nums) total += n;
        return total;
    }

    static string Format(string text, bool upper = false, string prefix = "")
    {
        string result = prefix + text;
        return upper ? result.ToUpper() : result;
    }

    static void Main()
    {
        Console.WriteLine(Sum(1, 2, 3));          // 6
        Console.WriteLine(Sum(10, 20, 30, 40));   // 100
        Console.WriteLine(Format("hello"));                    // hello
        Console.WriteLine(Format("hello", upper: true));       // HELLO
        Console.WriteLine(Format("hello", prefix: ">> "));     // >> hello
    }
}

