class Program
{
    static bool Divide(int a, int b, out int quotient, out int remainder)
    {
        if (b == 0) { quotient = 0; remainder = 0; return false; }
        quotient = a / b;
        remainder = a % b;
        return true;
    }

    static void Swap(ref int a, ref int b)
    {
        int temp = a;
        a = b;
        b = temp;
    }

    static void Main()
    {
        if (Divide(17, 5, out int q, out int r))
            Console.WriteLine($"{q} remainder {r}");  // 3 remainder 2

        int x = 10, y = 20;
        Swap(ref x, ref y);
        Console.WriteLine($"{x} {y}");  // 20 10
    }
}

