class Program
{
    static void ApplyAndPrint(int[] nums, Func<int, int> transform)
    {
        foreach (int n in nums)
            Console.Write(transform(n) + " ");
        Console.WriteLine();
    }

    static void ForEach(int[] nums, Action<int> action)
    {
        foreach (int n in nums) action(n);
    }

    static void Main()
    {
        int[] data = { 1, 2, 3, 4, 5 };
        ApplyAndPrint(data, x => x * x);       // 1 4 9 16 25
        ApplyAndPrint(data, x => x + 10);      // 11 12 13 14 15

        int sum = 0;
        ForEach(data, x => sum += x);
        Console.WriteLine(sum);                 // 15
    }
}

